   627→
   628→    /**
   629→     * @throws KafkaException if the rebalance callback throws exception
   630→     */
   631→    private ConsumerRecords<K, V> poll(final Timer timer) {
   632→        acquireAndEnsureOpen();
   633→        try {
   634→            this.kafkaConsumerMetrics.recordPollStart(timer.currentTimeMs());
   635→
   636→            if (this.subscriptions.hasNoSubscriptionOrUserAssignment()) {
   637→                throw new IllegalStateException("Consumer is not subscribed to any topics or assigned any partitions");
   638→            }
   639→
   640→            do {
   641→                client.maybeTriggerWakeup();
   642→
   643→                // try to update assignment metadata BUT do not need to block on the timer for join group
   644→                updateAssignmentMetadataIfNeeded(timer, false);
   645→
   646→                final Fetch<K, V> fetch = pollForFetches(timer);
   647→                if (!fetch.isEmpty()) {
   648→                    // before returning the fetched records, we can send off the next round of fetches
   649→                    // and avoid block waiting for their responses to enable pipelining while the user
   650→                    // is handling the fetched records.
   651→                    //
   652→                    // NOTE: since the consumed position has already been updated, we must not allow
   653→                    // wakeups or any other errors to be triggered prior to returning the fetched records.
   654→                    if (sendFetches() > 0 || client.hasPendingRequests()) {
   655→                        client.transmitSends();
   656→                    }
   657→
   658→                    if (fetch.records().isEmpty()) {
   659→                        log.trace("Returning empty records from `poll()` "
   660→                                + "since the consumer's position has advanced for at least one topic partition");
